package com.granpa.pumpselector;
import android.app.*;import android.content.*;import android.os.*;import android.text.*;import android.view.*;import android.widget.*;import java.util.*;
public class CatalogueActivity extends Activity{PumpListAdapter adapter;EditText search;Spinner cat;TextView count;
 protected void onCreate(Bundle b){super.onCreate(b);LinearLayout root=Ui.root(this);root.addView(Ui.text(this,"Catalogue / Model Search",26,Ui.TEXT,1));TextView note=Ui.text(this,"Use this screen for model search. Search by model, type, size, category or catalogue section. ACS1125 finds ACS 1125.",13,Ui.MUTED,0);Ui.mb(this,note,10);root.addView(note);search=Ui.input(this,"",android.text.InputType.TYPE_CLASS_TEXT);search.setHint("Search here, e.g. ACS1125, ASM SP, Openwell, 50");Ui.mb(this,search,10);root.addView(search);cat=Ui.spinner(this,categories());Ui.mb(this,cat,10);root.addView(cat);count=Ui.text(this,"",14,Ui.MUTED,1);Ui.mb(this,count,8);root.addView(count);adapter=new PumpListAdapter(this);ListView list=new ListView(this);list.setDivider(null);list.setCacheColorHint(0);list.setAdapter(adapter);root.addView(list,new LinearLayout.LayoutParams(-1,0,1));setContentView(root);TextWatcher w=new TextWatcher(){public void beforeTextChanged(CharSequence s,int st,int c,int a){}public void onTextChanged(CharSequence s,int st,int before,int count){refresh();}public void afterTextChanged(Editable e){}};search.addTextChangedListener(w);cat.setOnItemSelectedListener(new AdapterView.OnItemSelectedListener(){public void onItemSelected(AdapterView<?>p,View v,int pos,long id){refresh();}public void onNothingSelected(AdapterView<?>p){}});list.setOnItemClickListener((p,v,pos,id)->{PumpSelector.Result r=adapter.getResult(pos);Intent i=new Intent(this,PumpDetailsActivity.class);i.putExtra("id",r.r.id);startActivity(i);});refresh();}
 void refresh(){ArrayList<PumpSelector.Result> res=PumpSelector.catalogue(PumpRepository.getRecords(this),sel(cat),search.getText().toString());adapter.setItems(res);count.setText(res.size()+" catalogue models shown");}
 List<Option> categories(){ArrayList<Option> o=new ArrayList<>();o.add(new Option("all","All pump types","Main category • full catalogue",true));o.add(new Option("borewell_all","Borewell Submersible","Main category • borewell sections",true));o.add(new Option("openwell_all","Openwell Submersible","Main category • openwell sections",true));o.add(new Option("monoblock_all","Centrifugal / Surface Monoblock","Main category • self priming, jet, centrifugal and agricultural monoblock",true));o.add(new Option("multistage_all","Multistage Pumps","Main category • AVRS, vertical inline and horizontal multistage",true));o.add(new Option("dewatering_all","Dewatering / Sewage","Main category • sewage and dewatering pumps",true));o.add(new Option("motors_all","Motors","Main category • motor section",true));for(String c:PumpRepository.categories(this))o.add(new Option(c,"Sub category • "+c,"Detailed catalogue group",false));return o;}String sel(Spinner s){Object o=s.getSelectedItem();return o instanceof Option?((Option)o).value:String.valueOf(o);} }
